                {ageRanges.map(a => <option key={a} value={a}>{a}</option>)}
              </select>
              <input type="text" placeholder="Profession" value={form.profession} onChange={(e) => setForm({...form, profession: e.target.value})} required />
            </div>
            <div className="form-row">
              <input type="tel" placeholder="Téléphone" value={form.phone} onChange={(e) => setForm({...form, phone: e.target.value})} required />
              <select value={form.province} onChange={(e) => setForm({...form, province: e.target.value})} required>
                <option value="">Province de résidence</option>
                {provinces.map(p => <option key={p} value={p}>{p}</option>)}
              </select>
            </div>
            <div className="form-row">
              <select value={form.diaspora} onChange={(e) => setForm({...form, diaspora: e.target.value})}>
                <option value="">Diaspora ?</option>
                <option value="non">Non, je vis en RDC</option>
                <option value="oui">Oui, je vis à l'étranger</option>
              </select>
              <input type="text" placeholder="Autre résidence (pays/ville)" value={form.other_residence} onChange={(e) => setForm({...form, other_residence: e.target.value})} />
            </div>
