  const heritageImages = [
    { src: '/images/gallery/president-tshisekedi-rdc-fr.jpg', title: 'Félix Tshisekedi - Président de la République' },
    { src: '/images/gallery/forest-bassin-congo-fr.jpg', title: 'Bassin du Congo' },
    { src: '/images/gallery/okapi-espece-protegee-fr.jpg', title: 'Okapi - Espèce protégée' },
    { src: '/images/gallery/gorille-montagne-virunga-fr.jpg', title: 'Gorille des montagnes - Virunga' },
    { src: '/images/gallery/volcan-nyiragongo-goma-fr.jpg', title: 'Nyiragongo - Merveille naturelle' },
