// ==================== PROPOSAL SUBMISSION ====================
function SubmitProposal({ user }) {
  const [subject, setSubject] = useState('');
  const [oneSentence, setOneSentence] = useState('');
  const [content, setContent] = useState('');
  const [files, setFiles] = useState([]);
  const [images, setImages] = useState([]);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');

  const uploadFiles = async (fileList, bucket) => {
    const urls = [];
    for (const file of fileList) {
      const fileName = `${Date.now()}-${file.name}`;
      const { error } = await supabase.storage.from(bucket).upload(fileName, file);
      if (!error) {
        const { data } = supabase.storage.from(bucket).getPublicUrl(fileName);
        urls.push(data.publicUrl);
      }
    }
    return urls;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage('');

    const fileUrls = await uploadFiles(files, 'proposal-files');
    const imageUrls = await uploadFiles(images, 'proposal-images');

    const { error } = await supabase.from('proposals').insert([{
      user_id: user.id,
      subject,
      one_sentence: oneSentence,
      content,
      file_urls: fileUrls,
      image_urls: imageUrls,
      status: 'published'
    }]);

    if (error) setMessage('Erreur: ' + error.message);
    else {
      setMessage('Proposition soumise avec succès !');
      setSubject('');
      setOneSentence('');
      setContent('');
      setFiles([]);
      setImages([]);
    }
    setLoading(false);
  };

  return (
    <div className="submit-page">
      <div className="submit-card">
        <h2>Votre Proposition</h2>
        <p>Partagez votre vision pour la réforme constitutionnelle</p>
        {message && <div className="success">{message}</div>}
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Objet de votre proposition</label>
            <input type="text" placeholder="Maximum 250 caractères" maxLength="250" value={subject} onChange={(e) => setSubject(e.target.value)} required />
          </div>
          <div className="form-group">
            <label>Votre proposition en une phrase</label>
            <input type="text" placeholder="Résumez votre idée" value={oneSentence} onChange={(e) => setOneSentence(e.target.value)} required />
          </div>
          <div className="form-group">
            <label>Votre proposition détaillée</label>
            <textarea placeholder="Décrivez votre proposition en détail (minimum 100 caractères)" rows="10" value={content} onChange={(e) => setContent(e.target.value)} required />
          </div>
          <div className="form-group">
            <label>Images à joindre (optionnel)</label>
            <input type="file" multiple accept="image/*" onChange={(e) => setImages(Array.from(e.target.files))} />
          </div>
          <div className="form-group">
            <label>Documents Word/PDF (optionnel)</label>
            <input type="file" multiple accept=".pdf,.doc,.docx" onChange={(e) => setFiles(Array.from(e.target.files))} />
          </div>
          <div className="form-group checkbox">
            <label>
              <input type="checkbox" required /> J'accepte les conditions générales d'utilisation
            </label>
          </div>
          <button type="submit" disabled={loading} className="btn-gold btn-full">{loading ? 'Soumission...' : 'Publier ma proposition'}</button>
        </form>
      </div>
    </div>
  );
}

// ==================== PROPOSALS FEED WITH PAGINATION ====================
function ProposalsFeed({ user }) {
  const [proposals, setProposals] = useState([]);
  const [loading, setLoading] = useState(true);
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(true);
  const [profiles, setProfiles] = useState({});

  useEffect(() => {
    fetchProposals();
  }, [page]);

  useEffect(() => {
    fetchAllProfiles();
  }, []);

  const fetchAllProfiles = async () => {
    const { data } = await supabase.from('profiles').select('id, first_name, last_name, portrait_url');
    if (data) {
      const profileMap = {};
      data.forEach(p => { profileMap[p.id] = p; });
      setProfiles(profileMap);
    }
  };

  const fetchProposals = async () => {
    setLoading(true);
    const from = (page - 1) * 10;
    const to = from + 9;
    const { data, error } = await supabase
      .from('proposals')
      .select('*')
      .eq('status', 'published')
      .order('created_at', { ascending: false })
      .range(from, to);

    if (error) console.error(error);
    else {
      setProposals(prev => page === 1 ? data : [...prev, ...data]);
      setHasMore(data.length === 10);
    }
    setLoading(false);
  };

  const handleVote = async (proposalId, voteType) => {
    if (!user) {
      alert('Veuillez vous connecter pour voter');
      return;
    }
    // Check if user already voted
    const { data: existing } = await supabase
      .from('votes')
      .select('id')
      .eq('user_id', user.id)
      .eq('proposal_id', proposalId)
      .single();

    if (existing) {
      alert('Vous avez déjà voté sur cette proposition');
      return;
    }

    const { error } = await supabase.from('votes').insert([{
      user_id: user.id,
      proposal_id: proposalId,
      vote: voteType
    }]);

    if (!error) {
      if (voteType === 'yes') {
        await supabase.rpc('increment_vote', { proposal_id: proposalId, vote_column: 'yes_count' });
      } else {
        await supabase.rpc('increment_vote', { proposal_id: proposalId, vote_column: 'no_count' });
      }
      fetchProposals();
    } else {
      alert('Erreur: ' + error.message);
    }
  };

  return (
    <div className="feed-page">
      <div className="feed-header">
        <h1>Toutes les propositions</h1>
        {user && <Link to="/submit" className="btn-gold">+ Nouvelle proposition</Link>}
      </div>

      <div className="feed-grid">
        {proposals.map(p => {
          const profile = profiles[p.user_id];
          return (
            <div key={p.id} className="feed-card">
              <div className="feed-header-card">
                <img src={profile?.portrait_url || '/images/default-avatar.png'} alt="Avatar" className="feed-avatar" />
                <div className="feed-user">
                  <h4>{profile?.first_name} {profile?.last_name}</h4>
                  <small>{new Date(p.created_at).toLocaleDateString('fr-FR')}</small>
                </div>
                <div className="vote-stats">
                  <span className="vote-yes-count">✓ {p.yes_count || 0}</span>
                  <span className="vote-no-count">✗ {p.no_count || 0}</span>
                </div>
              </div>
              <h3 className="feed-subject">{p.subject}</h3>
              <p className="feed-one-sentence">"{p.one_sentence}"</p>
              <p className="feed-excerpt">{p.content?.substring(0, 200)}...</p>
              {p.image_urls && p.image_urls[0] && (
                <img src={p.image_urls[0]} alt="Illustration" className="feed-image" />
              )}
              {user && (
                <div className="vote-buttons">
                  <button onClick={() => handleVote(p.id, 'yes')} className="vote-yes">✓ OUI</button>
                  <button onClick={() => handleVote(p.id, 'no')} className="vote-no">✗ NON</button>
                </div>
              )}
              {!user && <p className="login-to-vote">Connectez-vous pour voter</p>}
            </div>
          );
        })}
      </div>

      {hasMore && !loading && (
        <button onClick={() => setPage(p => p + 1)} className="btn-gold load-more">Charger plus de propositions</button>
      )}
      {loading && <div className="loading-spinner">Chargement...</div>}
      {!hasMore && <p className="end-of-feed">Fin des propositions</p>}

      <Footer />
    </div>
  );
}

// ==================== STATISTICS PAGE WITH MAP ====================
function StatisticsPage() {
  const [stats, setStats] = useState({ totalProposals: 0, yesTotal: 0, noTotal: 0, totalUsers: 0 });
  const [keywords, setKeywords] = useState([]);
  const [provinceStats, setProvinceStats] = useState([]);

  useEffect(() => {
    fetchStats();
    fetchKeywords();
    fetchProvinceStats();
  }, []);

  const fetchStats = async () => {
    const { data: proposals } = await supabase.from('proposals').select('yes_count, no_count');
    const { count: totalUsers } = await supabase.from('profiles').select('*', { count: 'exact', head: true });
    let yesTotal = 0, noTotal = 0;
    proposals?.forEach(p => { yesTotal += p.yes_count || 0; noTotal += p.no_count || 0; });
    setStats({
      totalProposals: proposals?.length || 0,
      yesTotal,
      noTotal,
      totalUsers: totalUsers || 0
    });
  };

  const fetchKeywords = async () => {
    const { data: allProposals } = await supabase.from('proposals').select('content');
    const wordFreq = {};
    const stopWords = ['le', 'la', 'les', 'de', 'des', 'et', 'est', 'sont', 'pour', 'dans', 'avec', 'que', 'une', 'pas', 'plus', 'ce', 'ces', 'ses', 'lui', 'elle', 'nous', 'vous', 'ils', 'elles'];
    allProposals?.forEach(p => {
      const words = p.content?.toLowerCase().split(/\s+/) || [];
      words.forEach(w => {
        if (w.length > 3 && !stopWords.includes(w)) wordFreq[w] = (wordFreq[w] || 0) + 1;
      });
    });
    const sorted = Object.entries(wordFreq).sort((a,b) => b[1] - a[1]).slice(0, 15);
    setKeywords(sorted.map(([w, c]) => ({ word: w, count: c })));
  };

  const fetchProvinceStats = async () => {
    const { data } = await supabase.from('profiles').select('province');
    const provinceCount = {};
    data?.forEach(p => {
      if (p.province) provinceCount[p.province] = (provinceCount[p.province] || 0) + 1;
    });
    const sorted = Object.entries(provinceCount).sort((a,b) => b[1] - a[1]);
    setProvinceStats(sorted.map(([name, count]) => ({ name, count })));
  };

  return (
    <div className="stats-page">
      <div className="stats-header">
        <h1>Analyse des propositions citoyennes</h1>
        <p>Tableau de bord analytique</p>
      </div>

      <div className="stats-cards">
        <div className="stat-card">
          <div className="stat-num">{stats.totalProposals}</div>
          <div className="stat-label">Propositions soumises</div>
        </div>
        <div className="stat-card">
          <div className="stat-num">{stats.totalUsers}</div>
          <div className="stat-label">Citoyens participants</div>
        </div>
        <div className="stat-card">
          <div className="stat-num">{stats.yesTotal}</div>
          <div className="stat-label">Votes POUR (OUI)</div>
        </div>
        <div className="stat-card">
          <div className="stat-num">{stats.noTotal}</div>
          <div className="stat-label">Votes CONTRE (NON)</div>
        </div>
      </div>

      <div className="trends-section">
        <h3>📊 Tendances par province</h3>
        <div className="province-list">
          {provinceStats.map(p => (
            <div key={p.name} className="province-bar">
              <span className="province-name">{p.name}</span>
              <div className="bar-container">
                <div className="bar-fill" style={{ width: `${(p.count / (provinceStats[0]?.count || 1)) * 100}%` }}></div>
              </div>
              <span className="province-count">{p.count} citoyens</span>
            </div>
          ))}
        </div>
      </div>

      <div className="trends-section">
        <h3>🔍 Tendances par mots-clés</h3>
        <div className="keyword-cloud">
          {keywords.map(k => (
            <span key={k.word} className="keyword" style={{ fontSize: 16 + Math.min(k.count, 30) }}>
              {k.word}
            </span>
          ))}
        </div>
      </div>

      <Footer />
    </div>
  );
}

