// ==================== MAIN APP ====================
function App() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [proposals, setProposals] = useState([]);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUser(session?.user || null);
      setLoading(false);
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user || null);
    });
    fetchProposals();
    return () => subscription.unsubscribe();
  }, []);

  const fetchProposals = async () => {
    const { data } = await supabase
      .from('proposals')
      .select('*, profiles(first_name, last_name, portrait_url)')
      .eq('status', 'published')
      .limit(10)
      .order('created_at', { ascending: false });
    if (data) {
      const formatted = data.map(p => ({
        ...p,
        first_name: p.profiles?.first_name,
        last_name: p.profiles?.last_name,
        portrait_url: p.profiles?.portrait_url
      }));
      setProposals(formatted);
    }
  };

  if (loading) return <div className="loading-screen"><div className="loader"></div><p>Chargement du portail citoyen...</p></div>;

  return (
    <BrowserRouter>
      <nav className="navbar">
        <div className="nav-container">
          <Link to="/" className="nav-brand">
            <img src="/images/logo-drc-map.png" alt="RDC" className="nav-logo" />
            <span className="brand-text">MAONI | Réforme Constitutionnelle</span>
          </Link>
          <div className="nav-links">
            <Link to="/">Accueil</Link>
            <Link to="/proposals">Propositions</Link>
            <Link to="/statistics">Analyses</Link>
            {user && <Link to="/submit">Soumettre</Link>}
            {user ? (
              <button onClick={() => supabase.auth.signOut()} className="btn-outline">Déconnexion</button>
            ) : (
              <Link to="/login" className="btn-nav">Connexion</Link>
            )}
          </div>
        </div>
      </nav>
      <Routes>
        <Route path="/" element={<Homepage user={user} proposals={proposals} />} />
        <Route path="/proposals" element={<ProposalsFeed user={user} />} />
        <Route path="/statistics" element={<StatisticsPage />} />
        <Route path="/login" element={user ? <Navigate to="/" /> : <Login onLogin={setUser} />} />
        <Route path="/signup" element={user ? <Navigate to="/" /> : <Signup onSignup={setUser} />} />
        <Route path="/submit" element={user ? <SubmitProposal user={user} /> : <Navigate to="/login" />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
